SELECT total_matches
FROM team_history
WHERE team_id = 1;

SELECT COUNT(*) AS total_matches
FROM match_tournaments
WHERE tournament_id = 0;

SELECT player_id
FROM player_history
WHERE total_matches > 50;

SELECT total_matches AS total_matches_played
FROM venue_history
WHERE venue_id = 0;

SELECT AVG(th.total_matches) AS average_matches_played
FROM team_history th
WHERE (th.total_wins * 1.0 / th.total_matches) > 0.5;

SELECT MAX(highest_score) AS highest_score_in_t20
FROM matches
WHERE match_format = 'T20';

SELECT total_matches AS total_matches_played
FROM team_history
WHERE team_id = 1;
